const canvas = document.getElementById('mainCanvas');
const ctx = canvas.getContext('2d');
const zoomCanvas = document.getElementById('zoomCanvas');
const zoomCtx = zoomCanvas.getContext('2d');

let baseImage = new Image();
let medalImage = new Image();

let medalX = 494;
let medalY = 288;
let scaleW = 0.26;  // Start at 26%
let scaleH = 0.28;  // Start at 28%
let linkedScale = false;  // Unlinked since W/H differ
let medalBlur = 0.5;
let zoomLevel = 2.0;

let isDragging = false;
let dragOffsetX = 0;
let dragOffsetY = 0;

let displayScale = 1.0;
let showOverlay = true;

// Placements we've saved so far (seeded from the embedded DB)
const savedDatabase = {"placements": [{"name": "medal1", "x": 494, "y": 287, "w": 26, "h": 27, "blur": 1}]};
let placements = savedDatabase.placements || [];
let placementCounter = placements.length + 1;

// All available ribbon/medal images (base64-encoded)
const medalImages = [
    { name: "606_AF-OUT-CIVCR", src: "data:image/avif;base64," },
    { name: "612_ARM-EXCP-PUB", src: "data:image/avif;base64," },
    { name: "614_ARM-OUTS-CIV", src: "data:image/avif;base64," },
    { name: "618_CIV-VIET-SRV", src: "data:image/avif;base64," },
    { name: "639", src: "data:image/avif;base64," },
    { name: "660-G0275-SC", src: "data:image/avif;base64," },
    { name: "674", src: "data:image/avif;base64," },
    { name: "7221-IL", src: "data:image/avif;base64," },
    { name: "83869", src: "data:image/avif;base64," },
    { name: "83887", src: "data:image/avif;base64," },
    { name: "84016", src: "data:image/avif;base64," },
    { name: "84049", src: "data:image/avif;base64," },
    { name: "85494", src: "data:image/avif;base64," },
    { name: "85987", src: "data:image/avif;base64," },
    { name: "CAP145", src: "data:image/avif;base64," },
    { name: "YM-0027", src: "data:image/avif;base64," },
    { name: "YM-0028", src: "data:image/avif;base64," },
    { name: "606_AF-OUT-CIVCR2", src: "data:image/png;base64," },
    { name: "606_AF-OUT-CIVCR3", src: "data:image/png;base64," },
    { name: "606_AF-OUT-CIVCR4", src: "data:image/png;base64," }
];
let selectedMedalIndex = 0;

// Build the clickable medal grid in the left panel
function generateMedalTiles() {
    const container = document.getElementById('medalTiles');
    container.innerHTML = '';

    if (medalImages.length === 0) {
        container.innerHTML = '<div style="color: #64748b; font-size: 11px; grid-column: 1/-1;">No AVIF files found</div>';
        return;
    }

    medalImages.forEach((medal, index) => {
        const tile = document.createElement('div');
        tile.className = 'medal-tile' + (index === selectedMedalIndex ? ' selected' : '');
        tile.onclick = () => selectMedal(index);

        const img = document.createElement('img');
        img.src = medal.src;
        img.onerror = () => { img.style.display = 'none'; };
        tile.appendChild(img);

        const name = document.createElement('div');
        name.className = 'tile-name';
        name.textContent = medal.name;
        tile.appendChild(name);

        container.appendChild(tile);
    });
}

function selectMedal(index) {
    selectedMedalIndex = index;
    medalImage.src = medalImages[index].src;

    document.querySelectorAll('.medal-tile').forEach((tile, i) => {
        tile.classList.toggle('selected', i === index);
    });
}

// Kick off rendering once images are ready
baseImage.onload = function() {
    setupCanvas();
    render();
};
baseImage.src = 'data:image/jpeg;base64,';

medalImage.onload = function() {
    render();
};

// Wire everything up on page load
generateMedalTiles();
if (medalImages.length > 0) {
    medalImage.src = medalImages[selectedMedalIndex].src;
}

// Lock W and H together when the link button is active
function toggleLink() {
    linkedScale = !linkedScale;
    document.getElementById('linkBtn').classList.toggle('linked', linkedScale);
}

// Width and height slider wiring
document.getElementById('widthSlider').addEventListener('input', function(e) {
    setWidthAnchored(e.target.value / 100);
});

document.getElementById('heightSlider').addEventListener('input', function(e) {
    setHeightAnchored(e.target.value / 100);
});

function setWidthAnchored(newW) {
    scaleW = newW;
    if (linkedScale) {
        setHeightAnchored(newW, true);
    }
    document.getElementById('widthSlider').value = Math.round(scaleW * 100);
    document.getElementById('widthValue').textContent = Math.round(scaleW * 100) + '%';
    updatePositionDisplay();
    render();
}

function setHeightAnchored(newH, fromLink) {
    const oldH = medalImage.height * scaleH;
    const bottomY = medalY + oldH;

    scaleH = newH;

    const newHpx = medalImage.height * scaleH;
    medalY = bottomY - newHpx;

    if (linkedScale && !fromLink) {
        setWidthAnchored(newH, true);
    }

    document.getElementById('heightSlider').value = Math.round(scaleH * 100);
    document.getElementById('heightValue').textContent = Math.round(scaleH * 100) + '%';
    updatePositionDisplay();
    render();
}

function adjustWidth(delta) {
    const current = parseInt(document.getElementById('widthSlider').value);
    const newVal = Math.max(5, Math.min(200, current + delta));
    setWidthAnchored(newVal / 100);
}

function adjustHeight(delta) {
    const current = parseInt(document.getElementById('heightSlider').value);
    const newVal = Math.max(5, Math.min(200, current + delta));
    setHeightAnchored(newVal / 100);
}

// Blur slider goes 0-200 internally, maps to 0-20px in 0.1 steps
document.getElementById('blurSlider').addEventListener('input', function(e) {
    medalBlur = parseInt(e.target.value) / 10;
    document.getElementById('blurValue').textContent = medalBlur.toFixed(1) + 'px';
    render();
});

function adjustBlur(delta) {
    // delta is in 0.1px increments
    const current = parseInt(document.getElementById('blurSlider').value);
    const newVal = Math.max(0, Math.min(200, current + delta));
    medalBlur = newVal / 10;
    document.getElementById('blurSlider').value = newVal;
    document.getElementById('blurValue').textContent = medalBlur.toFixed(1) + 'px';
    render();
}

document.getElementById('zoomLevelSlider').addEventListener('input', function(e) {
    zoomLevel = e.target.value / 100;
    document.getElementById('zoomLevelValue').textContent = zoomLevel.toFixed(1) + 'x';
    renderZoom();
});

// Drag the medal around on the canvas
canvas.addEventListener('mousedown', function(e) {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) / displayScale;
    const y = (e.clientY - rect.top) / displayScale;

    const medalW = medalImage.width * scaleW;
    const medalH = medalImage.height * scaleH;

    const padding = 20;
    if (x >= medalX - padding && x <= medalX + medalW + padding &&
        y >= medalY - padding && y <= medalY + medalH + padding) {
        isDragging = true;
        dragOffsetX = x - medalX;
        dragOffsetY = y - medalY;
        canvas.style.cursor = 'grabbing';
    }
});

canvas.addEventListener('mousemove', function(e) {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) / displayScale;
    const y = (e.clientY - rect.top) / displayScale;

    document.getElementById('cursorX').textContent = Math.round(x);
    document.getElementById('cursorY').textContent = Math.round(y);

    if (isDragging) {
        medalX = x - dragOffsetX;
        medalY = y - dragOffsetY;
        updatePositionDisplay();
        render();
    }
});

canvas.addEventListener('mouseup', function() {
    isDragging = false;
    canvas.style.cursor = 'move';
});

canvas.addEventListener('mouseleave', function() {
    isDragging = false;
    canvas.style.cursor = 'move';
});

// Scroll wheel adjusts whichever dimension is linked
canvas.addEventListener('wheel', function(e) {
    e.preventDefault();
    const delta = e.deltaY > 0 ? -1 : 1;
    if (linkedScale) {
        adjustWidth(delta);
    } else {
        adjustHeight(delta);
    }
});

function setupCanvas() {
    const maxWidth = window.innerWidth;
    const maxHeight = window.innerHeight;

    displayScale = Math.min(maxWidth / baseImage.width, maxHeight / baseImage.height);

    canvas.width = baseImage.width * displayScale;
    canvas.height = baseImage.height * displayScale;
}

function render() {
    if (!baseImage.complete) return;

    showOverlay = document.getElementById('showOverlay').checked;

    ctx.save();
    ctx.scale(displayScale, displayScale);

    ctx.drawImage(baseImage, 0, 0);

    if (medalImage.complete && medalImage.width > 0) {
        const medalW = medalImage.width * scaleW;
        const medalH = medalImage.height * scaleH;
        const centerX = medalX + medalW / 2;
        const centerY = medalY + medalH / 2;

        // Offscreen canvas so we can apply blur + lighting
        const offCanvas = document.createElement('canvas');
        offCanvas.width = Math.ceil(medalW) + 10;
        offCanvas.height = Math.ceil(medalH) + 10;
        const offCtx = offCanvas.getContext('2d');

        // Draw the medal with optional blur
        if (medalBlur > 0) {
            offCtx.filter = 'blur(' + medalBlur + 'px)';
        }
        offCtx.drawImage(medalImage, 5, 5, medalW, medalH);
        offCtx.filter = 'none';

        // Subtle top highlight and bottom shadow for depth
        offCtx.globalCompositeOperation = 'source-atop';

        // Light edge at the top
        const highlightGrad = offCtx.createLinearGradient(0, 5, 0, 8);
        highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.4)');
        highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');
        offCtx.fillStyle = highlightGrad;
        offCtx.fillRect(0, 0, offCanvas.width, 8);

        // Dark edge at the bottom
        const shadowGrad = offCtx.createLinearGradient(0, 5 + medalH - 3, 0, 5 + medalH);
        shadowGrad.addColorStop(0, 'rgba(0, 0, 0, 0)');
        shadowGrad.addColorStop(1, 'rgba(0, 0, 0, 0.5)');
        offCtx.fillStyle = shadowGrad;
        offCtx.fillRect(0, 5 + medalH - 3, offCanvas.width, 8);

        offCtx.globalCompositeOperation = 'source-over';

        // Composite the medal onto the main canvas
        ctx.save();
        ctx.translate(centerX, centerY);
        ctx.drawImage(offCanvas, -medalW / 2 - 5, -medalH / 2 - 5);
        ctx.restore();

        if (showOverlay) {
            ctx.strokeStyle = 'cyan';
            ctx.lineWidth = 1 / displayScale;
            ctx.beginPath();
            ctx.moveTo(centerX - 15, centerY);
            ctx.lineTo(centerX + 15, centerY);
            ctx.moveTo(centerX, centerY - 15);
            ctx.lineTo(centerX, centerY + 15);
            ctx.stroke();

            ctx.fillStyle = 'cyan';
            ctx.font = (12 / displayScale) + 'px monospace';
            ctx.fillText('(' + Math.round(medalX) + ', ' + Math.round(medalY) + ')', medalX, medalY - 5);

            ctx.setLineDash([5 / displayScale, 5 / displayScale]);
            ctx.strokeRect(medalX, medalY, medalW, medalH);
            ctx.setLineDash([]);
        }
    }

    ctx.restore();
    renderZoom();
}

function renderZoom() {
    if (!baseImage.complete) return;

    const container = zoomCanvas.parentElement;
    zoomCanvas.width = container.clientWidth - 2;
    zoomCanvas.height = 150;

    const medalW = medalImage.width * scaleW;
    const medalH = medalImage.height * scaleH;
    const centerX = medalX + medalW / 2;
    const centerY = medalY + medalH / 2;

    const contextMultiplier = 0.6;
    const effectiveZoom = zoomLevel * contextMultiplier;

    const viewWidth = zoomCanvas.width / effectiveZoom;
    const viewHeight = zoomCanvas.height / effectiveZoom;
    const srcX = centerX - viewWidth / 2;
    const srcY = centerY - viewHeight / 2;

    zoomCtx.fillStyle = '#0a0a15';
    zoomCtx.fillRect(0, 0, zoomCanvas.width, zoomCanvas.height);

    zoomCtx.save();
    zoomCtx.scale(effectiveZoom, effectiveZoom);
    zoomCtx.translate(-srcX, -srcY);

    zoomCtx.drawImage(baseImage, 0, 0);

    if (medalImage.complete && medalImage.width > 0) {
        // Offscreen canvas so we can apply blur + lighting
        const offCanvas = document.createElement('canvas');
        offCanvas.width = Math.ceil(medalW) + 10;
        offCanvas.height = Math.ceil(medalH) + 10;
        const offCtx = offCanvas.getContext('2d');

        // Draw the medal with optional blur
        if (medalBlur > 0) {
            offCtx.filter = 'blur(' + medalBlur + 'px)';
        }
        offCtx.drawImage(medalImage, 5, 5, medalW, medalH);
        offCtx.filter = 'none';

        // Subtle top highlight and bottom shadow for depth
        offCtx.globalCompositeOperation = 'source-atop';

        // Light edge at the top
        const highlightGrad = offCtx.createLinearGradient(0, 5, 0, 8);
        highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.4)');
        highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');
        offCtx.fillStyle = highlightGrad;
        offCtx.fillRect(0, 0, offCanvas.width, 8);

        // Dark edge at the bottom
        const shadowGrad = offCtx.createLinearGradient(0, 5 + medalH - 3, 0, 5 + medalH);
        shadowGrad.addColorStop(0, 'rgba(0, 0, 0, 0)');
        shadowGrad.addColorStop(1, 'rgba(0, 0, 0, 0.5)');
        offCtx.fillStyle = shadowGrad;
        offCtx.fillRect(0, 5 + medalH - 3, offCanvas.width, 8);

        offCtx.globalCompositeOperation = 'source-over';

        // Composite the medal onto the zoom view
        zoomCtx.save();
        zoomCtx.translate(centerX, centerY);
        zoomCtx.drawImage(offCanvas, -medalW / 2 - 5, -medalH / 2 - 5);
        zoomCtx.restore();
    }

    zoomCtx.restore();

    const cx = zoomCanvas.width / 2;
    const cy = zoomCanvas.height / 2;
    zoomCtx.strokeStyle = 'rgba(0, 255, 255, 0.7)';
    zoomCtx.lineWidth = 1;
    zoomCtx.beginPath();
    zoomCtx.moveTo(cx - 20, cy);
    zoomCtx.lineTo(cx + 20, cy);
    zoomCtx.moveTo(cx, cy - 20);
    zoomCtx.lineTo(cx, cy + 20);
    zoomCtx.stroke();
}

function moveMedal(dx, dy) {
    const step = parseInt(document.getElementById('stepSize').value);
    medalX += dx * step;
    medalY += dy * step;
    updatePositionDisplay();
    render();
}

// Arrow keys also move the medal
document.addEventListener('keydown', function(e) {
    if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT') return;

    switch(e.key) {
        case 'ArrowUp':
            e.preventDefault();
            moveMedal(0, -1);
            break;
        case 'ArrowDown':
            e.preventDefault();
            moveMedal(0, 1);
            break;
        case 'ArrowLeft':
            e.preventDefault();
            moveMedal(-1, 0);
            break;
        case 'ArrowRight':
            e.preventDefault();
            moveMedal(1, 0);
            break;
    }
});

function updatePositionDisplay() {
    document.getElementById('posX').textContent = Math.round(medalX);
    document.getElementById('posY').textContent = Math.round(medalY);
}

function resetPosition() {
    medalX = 494;
    medalY = 288;
    scaleW = 0.26;
    scaleH = 0.28;
    linkedScale = false;
    medalBlur = 0.5;

    document.getElementById('widthSlider').value = 26;
    document.getElementById('widthValue').textContent = '26%';
    document.getElementById('heightSlider').value = 28;
    document.getElementById('heightValue').textContent = '28%';
    document.getElementById('blurSlider').value = 5;
    document.getElementById('blurValue').textContent = '0.5px';
    document.getElementById('linkBtn').classList.remove('linked');

    updatePositionDisplay();
    render();
}

function saveImage() {
    const saveCanvas = document.createElement('canvas');
    saveCanvas.width = baseImage.width;
    saveCanvas.height = baseImage.height;
    const saveCtx = saveCanvas.getContext('2d');

    saveCtx.drawImage(baseImage, 0, 0);

    if (medalImage.complete && medalImage.width > 0) {
        const medalW = medalImage.width * scaleW;
        const medalH = medalImage.height * scaleH;
        const centerX = medalX + medalW / 2;
        const centerY = medalY + medalH / 2;

        // Offscreen canvas so we can apply blur + lighting
        const offCanvas = document.createElement('canvas');
        offCanvas.width = Math.ceil(medalW) + 10;
        offCanvas.height = Math.ceil(medalH) + 10;
        const offCtx = offCanvas.getContext('2d');

        // Draw the medal with optional blur
        if (medalBlur > 0) {
            offCtx.filter = 'blur(' + medalBlur + 'px)';
        }
        offCtx.drawImage(medalImage, 5, 5, medalW, medalH);
        offCtx.filter = 'none';

        // Subtle top highlight and bottom shadow for depth
        offCtx.globalCompositeOperation = 'source-atop';

        // Light edge at the top
        const highlightGrad = offCtx.createLinearGradient(0, 5, 0, 8);
        highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.4)');
        highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');
        offCtx.fillStyle = highlightGrad;
        offCtx.fillRect(0, 0, offCanvas.width, 8);

        // Dark edge at the bottom
        const shadowGrad = offCtx.createLinearGradient(0, 5 + medalH - 3, 0, 5 + medalH);
        shadowGrad.addColorStop(0, 'rgba(0, 0, 0, 0)');
        shadowGrad.addColorStop(1, 'rgba(0, 0, 0, 0.5)');
        offCtx.fillStyle = shadowGrad;
        offCtx.fillRect(0, 5 + medalH - 3, offCanvas.width, 8);

        offCtx.globalCompositeOperation = 'source-over';

        // Composite the medal onto the export canvas
        saveCtx.save();
        saveCtx.translate(centerX, centerY);
        saveCtx.drawImage(offCanvas, -medalW / 2 - 5, -medalH / 2 - 5);
        saveCtx.restore();
    }

    const link = document.createElement('a');
    link.download = 'medal_preview_output.png';
    link.href = saveCanvas.toDataURL('image/png');
    link.click();
}

// Saving and loading medal positions
function addPlacement() {
    const name = 'medal' + placementCounter++;
    const x = Math.round(medalX);
    const y = Math.round(medalY);
    const w = Math.round(scaleW * 100);
    const h = Math.round(scaleH * 100);
    const blur = Math.round(medalBlur * 10) / 10;  // Round to 0.1

    placements.push({ name, x, y, w, h, blur });
    updatePlacementOutput();
    updatePresetDropdown();
}

function deleteLastPlacement() {
    if (placements.length > 0) {
        placements.pop();
        placementCounter = placements.length + 1;
        updatePlacementOutput();
        updatePresetDropdown();
    }
}

function updatePlacementOutput() {
    const output = document.getElementById('placementOutput');
    if (placements.length === 0) {
        output.textContent = 'No placements saved';
        return;
    }

    const lines = placements.map(p => {
        let str = p.name + '=' + p.x + ',' + p.y + '@';
        if (p.w === p.h) {
            str += p.w + '%';
        } else {
            str += p.w + '%x' + p.h + '%';
        }
        if (p.blur > 0) {
            str += ',blur=' + p.blur + 'px';
        }
        return str;
    });

    output.textContent = 'medalPlacements:\n' + lines.join('\n');
}

function updatePresetDropdown() {
    const select = document.getElementById('presetSelect');
    select.innerHTML = '<option value="">Load saved position...</option>';
    placements.forEach(p => {
        const opt = document.createElement('option');
        let val = p.x + ',' + p.y + '@';
        if (p.w === p.h) {
            val += p.w + '%';
        } else {
            val += p.w + '%x' + p.h + '%';
        }
        if (p.blur > 0) {
            val += ',blur=' + p.blur + 'px';
        }
        opt.value = val;
        opt.textContent = p.name + ' (' + p.x + ',' + p.y + ')';
        select.appendChild(opt);
    });
}

function copyPlacements() {
    const output = document.getElementById('placementOutput').textContent;
    navigator.clipboard.writeText(output).then(() => {
        alert('Placements copied to clipboard!');
    });
}

function saveDatabase() {
    const db = { placements: placements };
    const json = JSON.stringify(db, null, 2);

    fetch('/save-placements', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: json
    })
    .then(response => response.json())
    .then(data => {
        if (data.success) {
            alert('Database saved to placements.json!');
        } else {
            alert('Error: ' + (data.error || 'Unknown error'));
        }
    })
    .catch(err => {
        // No server? Just download the file instead
        const blob = new Blob([json], { type: 'application/json' });
        const link = document.createElement('a');
        link.download = 'placements.json';
        link.href = URL.createObjectURL(blob);
        link.click();
        alert('Server not running. File downloaded instead.\nRun: python serve.py');
    });
}

function clearPlacements() {
    if (confirm('Clear all placements?')) {
        placements = [];
        placementCounter = 1;
        updatePlacementOutput();
        updatePresetDropdown();
    }
}

function loadPreset() {
    const select = document.getElementById('presetSelect');
    const val = select.value;
    if (!val) return;

    // Format: x,y@w%xh%,blur=Npx  (h% and blur are optional)
    const match = val.match(/(-?\d+),(-?\d+)@(\d+)%(?:x(\d+)%)?(?:,blur=([\d.]+)px)?/);
    if (match) {
        medalX = parseInt(match[1]);
        medalY = parseInt(match[2]);
        scaleW = parseInt(match[3]) / 100;
        scaleH = match[4] ? parseInt(match[4]) / 100 : scaleW;
        medalBlur = match[5] ? parseFloat(match[5]) : 0;

        document.getElementById('widthSlider').value = Math.round(scaleW * 100);
        document.getElementById('widthValue').textContent = Math.round(scaleW * 100) + '%';
        document.getElementById('heightSlider').value = Math.round(scaleH * 100);
        document.getElementById('heightValue').textContent = Math.round(scaleH * 100) + '%';
        document.getElementById('blurSlider').value = Math.round(medalBlur * 10);
        document.getElementById('blurValue').textContent = medalBlur.toFixed(1) + 'px';

        updatePositionDisplay();
        render();
    }

    select.value = '';
}

// Re-fit the canvas when the browser resizes
window.addEventListener('resize', function() {
    setupCanvas();
    render();
});

// Show the starting state
updatePositionDisplay();
updatePresetDropdown();
updatePlacementOutput();
